message:
Running command: # OpenROAD Python not available directly.
# Use OpenROAD Tcl instead to check and fix VDDIO bterms.

cat > /tmp/fix_vddio.tcl << 'TCLEOF'
# Fix multiple VDDIO/VSSIO bterm pins before DRT
foreach net_name {VDDIO VSSIO VCCD VSSD} {
    set net [odb::dbNet_find [ord::get_db_block] $net_name]
    if { $net == "NULL" } {
        puts "Net $net_name: not found"
        continue
    }
    set bterms [$net getBTerms]
    puts "Net $net_name: [llength $bterms] bterms"
    foreach bterm $bterms {
        set bpins [$bterm getBPins]
        puts "  bterm [$bterm getName]: [llength $bpins] pins"
    }
}
TCLEOF

